function.body:
TYPE RECORD IS REF CURSOR;
Cur_Parameter RECORD;
  Cur_PaymentMethod RECORD;


  v_User_ID VARCHAR2(32) ;
  v_ClosingDate DATE;
  v_ResultStr VARCHAR2(2000) := '';
  v_Concept_ID VARCHAR2(32);
  v_LoadLines VARCHAR2(60);
  v_RecordId VARCHAR2(32);
  v_OrganizationId VARCHAR2(32);
  v_Contador NUMBER:=0; 
  v_TotalIncome NUMBER:=0; 
  v_TotalExpenses NUMBER:=0; 
  v_Docstatus VARCHAR2(60); 
  v_PeriodStatus  VARCHAR(60);--OBTG:VARCHAR2--
  v_ContadorLineas NUMBER:=0;
  v_TotalIncome2 NUMBER:=0; 
  v_TotalExpenses2 NUMBER:=0; 
  v_module NUMBER:=0; 
  v_Grandtotal NUMBER:=0; 
  v_type_payment  VARCHAR2(60);
  v_id  VARCHAR2(32);
  v_doctypesales VARCHAR2(32);
  v_doctypecreditnote VARCHAR2(32);
  v_totalpaymentmethod NUMBER:=0; 
  v_totalsales NUMBER:=0; 
  v_creditnotes NUMBER:=0; 
  v_setup_id VARCHAR2(32);
  v_preference VARCHAR2(60);
BEGIN

  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || PInstance_ID) ;
  v_ResultStr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

-- GET:    
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date,
        p.AD_Client_ID,
        p.AD_Org_ID,
        p.CreatedBy        
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
           ON i.AD_PInstance_ID = p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID = pinstance_id
      ORDER BY p.SeqNo
      )
    LOOP
        v_RecordId := Cur_Parameter.Record_ID;

      IF (Cur_Parameter.ParameterName = 'Ad_User_ID') THEN
        v_User_ID := Cur_Parameter.P_String;      
      END IF;    

    END LOOP;  

	SELECT cc.ad_org_id, cc.closingdate, c_doctype_sales_id, c_doctype_credit_notes_id, cc.sccc_setup_id
	INTO v_OrganizationId,v_ClosingDate, v_doctypesales, v_doctypecreditnote, v_setup_id
	FROM sccc_cash_clousure cc
	LEFT JOIN sccc_setup cs ON cc.sccc_setup_id = cs.sccc_setup_id
	WHERE sccc_cash_clousure_id= v_RecordId;

	 --COMPROBAR EXISTENCIA MÓDULO ec.com.sidesoft.custom.closecash.advanced
	SELECT 
	COALESCE((SELECT COUNT(*) AS CONTAR FROM AD_MODULE WHERE JAVAPACKAGE = 'ec.com.sidesoft.custom.closecash.advanced'),0)
	INTO v_Module
	FROM DUAL;

	--SE COMPRUEBA SI EL PERÍODO ESTÁ CERRADO
	SELECT openclose INTO v_PeriodStatus FROM c_period WHERE v_ClosingDate>=startdate AND v_ClosingDate <= enddate;
	IF ( v_PeriodStatus='O')THEN
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@PeriodNotAvailable@') ;
		RETURN;
	END IF;


	SELECT count(*) into v_Contador from sccc_payment_method pm
	INNER JOIN sccc_setup st ON st.sccc_setup_id = pm.sccc_setup_id
	WHERE st.ad_org_id= v_OrganizationId;

	IF (v_Contador =0) THEN

	    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@SCCC_ORG_NOT_FOUND@') ;
		RETURN;
	END IF;

    SELECT COALESCE(( 	SELECT value
                        FROM ad_preference
                        WHERE property = 'Sccc_CloseCashDoctype'
                        AND created = ( SELECT MAX(created) FROM ad_preference 
                        WHERE property = 'Sccc_CloseCashDoctype')
                ),'N')
    INTO v_preference
    FROM DUAL;  

	IF (v_preference='Y' AND (v_doctypesales IS NULL OR v_doctypecreditnote IS NULL)) THEN
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_DocTypeNull@') ;
		RETURN;		
	END IF;

	IF(v_preference='Y' AND v_setup_id IS NULL) THEN
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_SetupNotSet@') ;
		RETURN;			
	END IF;

	FOR Cur_PaymentMethod IN
	      (SELECT pm.fin_paymentmethod_id,order_number,typeaccount,pm.blind  
	      FROM sccc_payment_method pm
	      INNER JOIN sccc_setup st ON st.sccc_setup_id = pm.sccc_setup_id
		WHERE ((st.ad_org_id= v_OrganizationId AND v_preference='N') OR (pm.sccc_setup_id=v_setup_id AND v_preference='Y')  ) 
	       ORDER BY order_number)
	LOOP

	v_totalpaymentmethod := 0;
	IF (Cur_PaymentMethod.blind = 'N') THEN 

		IF (v_preference='N') THEN

			SELECT 
			SUM(
			CASE WHEN dt.isreversal='Y' OR dt.isreturn='Y' THEN
				abs(ci.totalpaid)*-1
			ELSE
				ci.totalpaid
			END
			) INTO v_totalpaymentmethod
			FROM c_invoice ci
			LEFT JOIN c_doctype dt ON ci.c_doctype_id = dt.c_doctype_id
			WHERE ci.docstatus='CO' AND ci.issotrx='Y' 
			AND ci.ad_org_id=v_OrganizationId AND TO_DATE(ci.dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy')
			AND ci.fin_paymentmethod_id = Cur_PaymentMethod.fin_paymentmethod_id;

		ELSE

			SELECT sum(totalpaid) INTO v_totalsales
			FROM c_invoice
			WHERE fin_paymentmethod_id = Cur_PaymentMethod.fin_paymentmethod_id
			AND TO_DATE(dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy') AND c_doctype_id = v_doctypesales
			AND docstatus='CO' AND issotrx='Y';

			SELECT sum(totalpaid) INTO v_creditnotes
			FROM c_invoice
			WHERE fin_paymentmethod_id = Cur_PaymentMethod.fin_paymentmethod_id
			AND TO_DATE(dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy') AND c_doctype_id = v_doctypecreditnote
			AND docstatus='CO' AND issotrx='Y';	

			v_totalpaymentmethod := ABS(COALESCE(v_totalsales,0))-ABS(COALESCE(v_creditnotes,0));

		END IF;

	END IF;

	v_totalpaymentmethod = COALESCE(v_totalpaymentmethod,0);

	v_id = get_uuid();

	INSERT INTO sccc_cash_clousureline(
            sccc_cash_clousureline_id, ad_client_id, ad_org_id, ad_user_id, 
            isactive, created, createdby, updated, updatedby, fin_paymentmethod_id, order_number, typeaccount, sccc_cash_clousure_id, amount)
	VALUES (v_id,(select ad_client_id from sccc_cash_clousure where sccc_cash_clousure_id= v_RecordId ),
	   (select ad_org_id from sccc_cash_clousure where sccc_cash_clousure_id= v_RecordId ), 
	   (select ad_user_id from sccc_cash_clousure where sccc_cash_clousure_id= v_RecordId ), 
            'Y', now(), v_User_ID, now(), v_User_ID, Cur_PaymentMethod.fin_paymentmethod_id,Cur_PaymentMethod.order_number,Cur_PaymentMethod.typeaccount, v_RecordId, v_totalpaymentmethod);


	IF (v_Module>0) THEN
		EXECUTE IMMEDIATE 'SELECT em_scca_type_payment FROM fin_paymentmethod pm WHERE pm.fin_paymentmethod_id ='''|| Cur_PaymentMethod.fin_paymentmethod_id || '''' INTO v_type_payment; 

		IF (v_type_payment IS NULL) THEN
			EXECUTE IMMEDIATE 'UPDATE sccc_cash_clousureline SET em_scca_paymenttype= NULL WHERE sccc_cash_clousureline_id='''||v_id||'''' ; 
		ELSE
			EXECUTE IMMEDIATE 'UPDATE sccc_cash_clousureline SET em_scca_paymenttype='''|| v_type_payment || ''' WHERE sccc_cash_clousureline_id='''||v_id||'''' ; 
		END IF;

	END IF;

    END LOOP;  


    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, '@Success@') ;
    RETURN;


  END; --BODY
  EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END SCCC_LOADLINES
